mapper.select:
SELECT id,
       request_id,
       trace_id,
       actor_type,
       operator_user_id,
       operator_username,
       operator_role_code,
       actor_department_id,
       patient_user_id,
       encounter_id,
       access_action,
       access_purpose_code,
       resource_type,
       resource_id,
       access_result,
       deny_reason_code,
       client_ip,
       user_agent,
       occurred_at,
       created_at
FROM audit.data_access_log
WHERE 1 = 1

    AND occurred_at >= #{from}


    AND occurred_at <= #{to}


    AND resource_type = #{resourceType}


    AND resource_id = #{resourceId}


    AND operator_user_id = #{operatorUserId}


    AND patient_user_id = #{patientUserId}


    AND encounter_id = #{encounterId}


    AND access_action = #{accessAction}


    AND access_result = #{accessResult}


    AND request_id = #{requestId}

ORDER BY occurred_at DESC, id DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1)
FROM audit.data_access_log
WHERE 1 = 1

    AND occurred_at >= #{from}


    AND occurred_at <= #{to}


    AND resource_type = #{resourceType}


    AND resource_id = #{resourceId}


    AND operator_user_id = #{operatorUserId}


    AND patient_user_id = #{patientUserId}


    AND encounter_id = #{encounterId}


    AND access_action = #{accessAction}


    AND access_result = #{accessResult}


    AND request_id = #{requestId}
